#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::CSV;

# Function to extract information from the PDF
sub extract_pdf_data {
    my ($pdf_file) = @_;

    # Open the PDF file
    my $pdf = PDF::API2->open($pdf_file);

    # Get the first page
    my $page = $pdf->openpage(1);

    # Extract text from the page
    my $text = $page->text;

    # Find and extract the date and author
    my ($date, $author);
    while ($text =~ /(\d{1,2}\s+\w+\s+\d{4})|([\w\s]+Author:\s+\w+\s+\w+)/g) {
        if (/(\d{1,2}\s+\w+\s+\d{4})/) {
            $date = $1;
        } elsif (/([\w\s]+Author:\s+\w+\s+\w+)/) {
            $author = $1;
        }
    }

    # Find and extract tables
    my $tables = $page->tables;
    my @table_data;
    foreach my $table (@$tables) {
        my @rows;
        foreach my $row (@$table) {
            my @cells = map { $_->text } @$row;
            push @rows, \@cells;
        }
        push @table_data, \@rows;
    }

    return ($date, $author, \@table_data);
}

